# ──────────────────────────────────────────────────────────
# part1.ps1 — ساخت پوشه و نوشتن بخش اول فایل HTML
# ──────────────────────────────────────────────────────────

$projectDir = "$env:USERPROFILE\Desktop\Freedom_Article"
if (-not (Test-Path $projectDir)) { New-Item -ItemType Directory -Path $projectDir | Out-Null }

$part1 = @'
